// src/components/charts/AlertStateChart.jsx
import React from "react";
import { Bar } from "react-chartjs-2";
import {
  Chart as ChartJS,
  CategoryScale,
  LinearScale,
  BarElement,
  Title,
  Tooltip,
  Legend,
} from "chart.js";

ChartJS.register(CategoryScale, LinearScale, BarElement, Title, Tooltip, Legend);

export function AlertStateChart({ data = [] }) {
  const labels = data.map((d, idx) => {
    const ts = d.timestamp || d._time;
    if (!ts) return `${idx + 1}`;
    return new Date(ts).toLocaleTimeString();
  });
  const chartData = {
    labels,
    datasets: [
      {
        label: "Alert State",
        data: data.map(d => (d.state === "ATTACK" ? 1 : 0)),
        backgroundColor: data.map(d => (d.state === "ATTACK" ? "red" : "green")),
      },
    ],
  };

  const options = {
    responsive: true,
    plugins: { legend: { display: false }, title: { display: true, text: "Alert State Over Time" } },
    scales: { y: { beginAtZero: true, ticks: { stepSize: 1 } } },
  };

  return <Bar data={chartData} options={options} />;
}
